#include <stdio.h>
int main()
{
    char str[7];
    scanf("%s", str);
    int i, sum1 = 0, sum2 = 0;
    for (i = 0; i < 3; i++)
    {
        sum1 += str[i] - '0';
    }
    for (i = 3; i < 6; i++)
    {
        sum2 += str[i] - '0';
    }
    if (sum1 == sum2)
    {
        printf("0");
    }
    else
    {
        printf("1");
    }
    return 0;
}
